Application.prose:
import { ITtscGraphDetails } from "./ITtscGraphDetails";
import { ITtscGraphEntrypoints } from "./ITtscGraphEntrypoints";
import { ITtscGraphEscape } from "./ITtscGraphEscape";
import { ITtscGraphLookup } from "./ITtscGraphLookup";
import { ITtscGraphNext } from "./ITtscGraphNext";
import { ITtscGraphOverview } from "./ITtscGraphOverview";
import { ITtscGraphTour } from "./ITtscGraphTour";
import { ITtscGraphTrace } from "./ITtscGraphTrace";
/** ## Code Graph MCP `inspect_typescript_graph` returns a compiler-built TypeScript graph contract for the current on-disk source snapshot. Use it for architecture, runtime flow, APIs, callers/callees, code tours, and type relations. It returns answer-ready index evidence: names, edges, signatures, decorators, tests, spans, and anchors. Every returned fact — each name, edge, signature, and span — is compiler-resolved and verified for the snapshot that call synchronized, so trust it without re-checking against files. Where an operation ranks a shortlist against your question (`lookup`, `entrypoints`, `tour`), the facts stay verified but the selection is heuristic: judge whether its coverage answers you, and a follow-up request or a read of a cited span is fair when it does not. ## Requests A request is a union: pick the single type below that best fits the question, and submit exactly that one. - `tour`: architecture, runtime flow, orientation, or a code tour. One call is the whole answer; do not split it. Name the machinery you expect it to be made of in its `reinterpretations`, or send none. - `entrypoints`: find where execution starts when entry points are unknown. - `lookup`: locate a named symbol. - `trace`: follow calls or data flow forward or backward from a symbol, or — with `to` — the path between two symbols when both ends are known, which is the one call that answers "how does A reach B". - `details`: signatures, members, and relations of named symbols — including the classes that implement an interface, which is the one call that answers "what actually implements this". - `overview`: project layers and folder structure. - `escape`: the answer is outside the graph (source body text, non-TypeScript files, exact search). ## Chain of Thought Fill these fields in order before the call; each one narrows the reasoning toward the single request you submit. - `question`: the code question, in the user's own words. - `draft`: `{ reason, type }` — why the smallest request that could answer it, then that request's `type`. - `review`: fix a broad, stale, or duplicate draft. If the graph already answered, or the evidence is outside it, escape. - `request`: the final choice. Each branch documents its own fields; fill them from what the branch says, not from what another branch wanted. ## What to trust Before source edits, every returned fact is compiler-resolved and verified. Never use extra graph calls, repository search, or file reads to doubt, fact-check, re-derive, re-narrate, or re-confirm a returned node, span, edge, signature, decorator, test, reference, step, or anchor. The server resolved each one to the type-checked program for the snapshot the call synced to, and `audit` says so on every result. Selection is the separate question. `lookup`, `entrypoints`, and `tour` match your question and return a scored, ranked, per-file-capped, limited shortlist; their facts are still verified, but whether the shortlist covers what you asked is yours to judge, and their `audit` says that instead of claiming completeness. A follow-up request or a read of a cited span for missed coverage is legitimate — re-confirming a fact the graph already resolved is not. ## Stop Let the result's `next` set the pace, and do not re-confirm what the graph resolved. - A span is a citation, not a cue to open the file to re-check a fact. - Follow the result's `next`: `answer` means stop and answer from it, `inspect` means make exactly the one request it names, `outside` means escape, `clarify` means restate the request. - For a ranked shortlist (`lookup`, `entrypoints`, `tour`), `next` and `truncated` say whether coverage is settled; when it is not, one more request is the right move — not a file read to re-verify facts already given. */
export interface ITtscGraphApplication {
/** Answer a TypeScript question from the compiler's own index of this repository. The graph holds every symbol, call, type, decorator and test, each with its file and line, resolved from the source on disk now. Submit exactly one request: - `tour`: architecture, the runtime flow from the public API to the code that does the work, nearby paths, and the tests to read — a whole orientation in one call - `trace`: what a symbol calls, what calls it, or the path from A to B - `details`: signatures, members, and what implements an interface - `lookup`: where a named symbol is declared - `entrypoints`: where execution starts, when the entry is unknown - `overview`: the project's layers and folder structure Every fact in a result is the checker's own resolution, audited before return, so no fact needs verifying; for the ranked operations (`lookup`, `entrypoints`, `tour`), judge whether the shortlist covers your question. Read a file for what the graph does not carry: a body, the text in a span. @param props Reasoning plus one graph request @returns Matching `result` union member */
inspect_typescript_graph(
props: ITtscGraphApplication.IProps,
): Promise<ITtscGraphApplication.IOutput>;
}
export namespace ITtscGraphApplication {
/** Draft, review, then submit exactly one graph request or escape. */
export interface IProps {
/** The code question, in the user's own words. Cut a long message down to the sentences that state the ask, but keep their terms: the graph ranks against these words, so a rewrite ranks a different answer. */
question: string;
/** The smallest request that could answer, and why. */
draft: IDraft;
/** Correct the draft. Escape if the graph already answered, or the next evidence is outside the graph. */
review: string;
/** Final graph request chosen after review, or a no-op escape. */
request:
| ITtscGraphEntrypoints.IRequest
| ITtscGraphLookup.IRequest
| ITtscGraphTrace.IRequest
| ITtscGraphDetails.IRequest
| ITtscGraphOverview.IRequest
| ITtscGraphTour.IRequest
| ITtscGraphEscape.IRequest;
}
/** First-pass plan; `reason` precedes `type` so it is written first. */
export interface IDraft {
/** Why this is the smallest useful next step. */
reason: string;
/** The request type being considered. */
type: IProps["request"]["type"];
}
/** The selected request's output. `result.type` mirrors `request.type`. */
export interface IOutput {
/** What the server audited this result against before returning it, in its own words: every node, span, edge, signature, member, and step in it resolves to the type-checked program for the snapshot the call synced to, so opening a file it cites only returns a fact already in it. The audit is operation-aware. For the exact operations (`trace`, `details`, `overview`) it reports the result as the structure the graph holds for the handles named, bounded only where `truncated` says. For the ranked operations (`lookup`, `entrypoints`, `tour`) it adds that the selection is heuristic — matched, scored, ranked, and limited against the question — so the facts are verified but the shortlist's coverage is the caller's to judge. */
audit: string;
/** What to do with `result`: answer, inspect one named request, or escape. */
next: ITtscGraphNext;
/** Result branch matching the submitted `request.type`. */
result:
| ITtscGraphEntrypoints
| ITtscGraphLookup
| ITtscGraphTrace
| ITtscGraphDetails
| ITtscGraphOverview
| ITtscGraphTour
| ITtscGraphEscape;
}
}

