export interface ITtscGraphDump {
project: string;
tsconfig: string;
nodes: ITtscGraphDump.INode[];
edges: ITtscGraphDump.IEdge[];
}
export namespace ITtscGraphDump {
export interface INode extends Omit<
ITtscGraphNode,
"evidence" | "implementation"
