Escape.prose:
/** The no-op result for when graph is not the useful next evidence source. */
export interface ITtscGraphEscape {
/** Discriminator for the no-op escape route. */
type: "escape";
/** Always true so callers can distinguish an intentional no-op. */
skipped: true;
/** Why no graph operation should run. */
reason: string;
/** Optional note about the next non-graph step. */
nextStep?: string;
}
export namespace ITtscGraphEscape {
/** Skip graph work when graph evidence is unnecessary or exhausted. */
export interface IRequest {
/** Discriminator for the no-op escape route. */
type: "escape";
/** Why no graph operation should run. Use only when the next evidence is outside the indexed graph: package scripts, config files, generated output, prose docs, exact text, or source body text. Name the smallest returned sourceSpan when source body text is truly required. */
reason: string;
/** A short final non-graph note, if useful, for example `answer from the prior graph result` or `source body needed at returned sourceSpan`. */
nextStep?: string;
}
}

Evidence.structure:
export interface ITtscGraphEvidence {
file: string;
startLine: number;
startCol?: number;
endLine?: number;
endCol?: number;
}

Evidence.prose:
/** A source location grounding a node or edge in real code: the declaration span for a node, or the expression range that produced an edge. Display and grounding only, never identity (a node's id is position-invariant, see {@link ITtscGraphNode}). Lines and columns are 1-based; MCP keeps evidence as coordinates, so read the file yourself when you truly need source text. */
export interface ITtscGraphEvidence {
/** Project-relative path of the file the span lives in. */
file: string;
/** 1-based line where the span starts. */
startLine: number;
/** 1-based column where the span starts, when known. */
startCol?: number;
/** 1-based line where the span ends, when it differs from `startLine`. */
endLine?: number;
/** 1-based column where the span ends, when known. */
endCol?: number;
}

